#!/usr/bin/env python3
"""
    ╔═══════════════════════════════════════════════════════════════╗
    ║                                                               ║
    ║          A N D U R I L   T R A D I N G   S U I T E           ║
    ║                                                               ║
    ║             "Flame of the West  --  Reforged"                 ║
    ║                                                               ║
    ╚═══════════════════════════════════════════════════════════════╝

    Anduril v1.0  --  Cross-platform installer
    Supports: macOS (Apple Silicon + Intel)  |  Windows 10/11  |  Linux
    Python 3.12+ required

    Usage:
        python install.py
"""

import os, sys, subprocess, shutil, platform, time, textwrap
from pathlib import Path
import base64, ast

_steps_total = 0
_steps_done  = 0

# ──────────────────────────────────────────────────────────────────
# CONSTANTS
# ──────────────────────────────────────────────────────────────────
VERSION      = "1.0.0"
PYTHON_MIN   = (3, 12)
INSTALL_ROOT = Path.home() / "Anduril"
DASH_DIR     = INSTALL_ROOT / "dashboard"
VENV_DIR     = INSTALL_ROOT / "venv"
ENV_FILE     = INSTALL_ROOT / ".env.trading"
IS_WIN       = platform.system() == "Windows"
IS_MAC       = platform.system() == "Darwin"
IS_LINUX     = platform.system() == "Linux"
IS_ARM       = platform.machine() in ("arm64", "aarch64")

PYTHON_EXE   = str(VENV_DIR / ("Scripts" if IS_WIN else "bin") / ("python.exe" if IS_WIN else "python"))
PIP_EXE      = str(VENV_DIR / ("Scripts" if IS_WIN else "bin") / ("pip.exe"    if IS_WIN else "pip"))
LAUNCH_EXE   = str(INSTALL_ROOT / ("launch.bat" if IS_WIN else "launch.sh"))

PACKAGES = [
    "numpy", "pandas", "scipy",
    "plotly>=5.18", "dash>=2.14", "dash-bootstrap-components",
    "yfinance>=0.2", "finnhub-python", "ta",
    "python-dotenv", "requests", "websocket-client",
    "vaderSentiment", "jupyterlab", "ipywidgets",
    "backtesting", "rich", "tqdm",
]

# ──────────────────────────────────────────────────────────────────
# COLORS  (ANSI -- works on Mac/Linux; Windows 10+ with VT enabled)
# ──────────────────────────────────────────────────────────────────
if IS_WIN:
    os.system("color")   # enable VT100 on Windows terminal

R  = "\033[0;31m";  G  = "\033[0;32m";  Y  = "\033[38;5;208m"
C  = "\033[38;5;99m";  W  = "\033[1;37m";  M  = "\033[38;5;208m"
DIM= "\033[2m";     NC = "\033[0m"

def clr(color, text): return f"{color}{text}{NC}"
def banner_line(text="", width=65):
    pad = (width - len(text)) // 2
    return f"  {clr(C, '║')}  {' ' * pad}{clr(W, text)}{clr(C, '  ║')}"

# ──────────────────────────────────────────────────────────────────
# BANNER
# ──────────────────────────────────────────────────────────────────
def print_banner():
    sword = [
        "                    /|",
        "                   / |",
        "                  /  |",
        "      ___________/   |",
        "     |  ANDURIL  >=======)",
        "     |___________|  |",
        "                  |  |",
        "                  |  |",
        "                  +--+",
    ]
    print()
    print(clr(C, "  " + "═" * 63))
    print(clr(C, "  ║") + " " * 63 + clr(C, "║"))
    for line in sword:
        pad_r = 63 - len(line) - 2
        print(clr(C, "  ║") + clr(Y, "  " + line) + " " * max(0, pad_r) + clr(C, "║"))
    print(clr(C, "  ║") + " " * 63 + clr(C, "║"))
    print(clr(C, "  ║") + clr(W, "      A N D U R I L   T R A D I N G   S U I T E      ") + "   " + clr(C, "║"))
    print(clr(C, "  ║") + clr(DIM, "             Flame of the West  --  Reforged             ") + clr(C, "║"))
    print(clr(C, "  ║") + " " * 63 + clr(C, "║"))
    plat = f"{'macOS' if IS_MAC else 'Windows'} {'arm64' if IS_ARM else platform.machine()}  |  Python {sys.version.split()[0]}"
    pad = (61 - len(plat)) // 2
    print(clr(C, "  ║") + " " * (pad+2) + clr(DIM, plat) + " " * (61 - pad - len(plat)) + clr(C, "║"))
    print(clr(C, "  ║") + " " * 63 + clr(C, "║"))
    print(clr(C, "  " + "═" * 63))
    print()

# ──────────────────────────────────────────────────────────────────
# LOGGING
# ──────────────────────────────────────────────────────────────────
_steps_total = 0
_steps_done  = 0

def section(title):
    print()
    print(clr(C, "  ┌─ ") + clr(W, title.upper()) + clr(C, " " + "─" * max(0, 56 - len(title)) + "┐"))

def step(msg):
    global _steps_done
    _steps_done += 1
    bar = clr(DIM, f"[{_steps_done:>2}/{_steps_total}]")
    print(f"  {bar}  {clr(Y, '▸')}  {msg}")

def ok(msg):
    print(f"  {clr(G, '  ✓')}  {msg}")

def warn(msg):
    print(f"  {clr(Y, '  ⚠')}  {msg}")

def fail(msg):
    print(f"  {clr(R, '  ✗')}  {msg}")
    sys.exit(1)

def progress_bar(label, n, total, width=30):
    filled = int(width * n / total)
    bar = clr(G, "█" * filled) + clr(DIM, "░" * (width - filled))
    pct = f"{n/total*100:.0f}%"
    print(f"  {clr(DIM, label):<30}  [{bar}]  {clr(W, pct)}", end="\r")
    if n == total:
        print()

# ──────────────────────────────────────────────────────────────────
# HELPERS
# ──────────────────────────────────────────────────────────────────
def run(cmd, check=True, capture=False, **kw):
    result = subprocess.run(
        cmd, shell=isinstance(cmd, str),
        capture_output=capture, text=True, **kw)
    if check and result.returncode != 0:
        if capture:
            fail(f"Command failed: {cmd}\n{result.stderr or result.stdout}")
        else:
            fail(f"Command failed: {cmd}")
    return result

def check_disk_space(min_gb=3):
    usage = shutil.disk_usage(Path.home())
    free_gb = usage.free / 1e9
    if free_gb < min_gb:
        fail(f"Need at least {min_gb}GB free. Only {free_gb:.1f}GB available.")
    return free_gb

def internet_check():
    import urllib.request
    try:
        urllib.request.urlopen("https://pypi.org", timeout=5)
        return True
    except:
        return False

def check_python_version():
    v = sys.version_info
    if (v.major, v.minor) < PYTHON_MIN:
        fail(f"Python {PYTHON_MIN[0]}.{PYTHON_MIN[1]}+ required. "
             f"You have {v.major}.{v.minor}.{v.micro}\n"
             f"  Download from: https://www.python.org/downloads/")

# ──────────────────────────────────────────────────────────────────
# PRE-FLIGHT
# ──────────────────────────────────────────────────────────────────
def preflight():
    section("Pre-Flight Check")
    global _steps_total
    _steps_total = 8

    step("Python version"); check_python_version()
    ok(f"Python {sys.version.split()[0]}")

    step("Platform")
    plat = f"{'macOS' if IS_MAC else 'Windows'} {platform.release()} ({'arm64' if IS_ARM else platform.machine()})"
    ok(plat)

    step("Disk space")
    free = check_disk_space(3)
    ok(f"{free:.1f} GB free")

    step("Internet connection")
    if not internet_check():
        fail("No internet. Connect and retry.")
    ok("Connected")

    step("Git")
    if shutil.which("git"):
        r = run("git --version", capture=True); ok(r.stdout.strip())
    else:
        warn("Git not found -- not required but recommended")

    step("Install directory")
    INSTALL_ROOT.mkdir(parents=True, exist_ok=True)
    DASH_DIR.mkdir(parents=True, exist_ok=True)
    (INSTALL_ROOT / "notebooks").mkdir(exist_ok=True)
    ok(str(INSTALL_ROOT))

    print()
    confirm = input(f"  {clr(W, 'Install Anduril Trading Suite?')}  {clr(DIM, '[y/N]')}  ").strip().lower()
    if confirm not in ("y", "yes"):
        print(f"  {clr(DIM, 'Cancelled.')}"); sys.exit(0)

# ──────────────────────────────────────────────────────────────────
# VIRTUAL ENVIRONMENT
# ──────────────────────────────────────────────────────────────────
def setup_venv():
    section("Virtual Environment")
    global _steps_done, _steps_total
    _steps_total += 3

    step("Creating virtual environment")
    if VENV_DIR.exists():
        ok("Already exists")
    else:
        run([sys.executable, "-m", "venv", str(VENV_DIR)])
        ok(f"Created at {VENV_DIR}")

    step("Upgrading pip")
    run([PYTHON_EXE, "-m", "pip", "install", "--upgrade", "pip", "setuptools", "wheel", "-q"])
    ok("pip up to date")

    # Fix pip cache permissions on Mac if needed
    if IS_MAC:
        cache = Path.home() / "Library" / "Caches" / "pip"
        if cache.exists():
            step("Fixing pip cache permissions")
            run(["chown", "-R", os.environ.get("USER", ""), str(cache)], check=False)
            ok("Cache permissions fixed")
        else:
            _steps_done += 1

# ──────────────────────────────────────────────────────────────────
# PACKAGES
# ──────────────────────────────────────────────────────────────────
def install_packages():
    section("Installing Packages")
    global _steps_total
    _steps_total += len(PACKAGES)

    for i, pkg in enumerate(PACKAGES, 1):
        step(f"{pkg}")
        result = run(
            [PYTHON_EXE, "-m", "pip", "install", pkg, "-q"],
            check=False, capture=True)
        if result.returncode != 0:
            warn(f"  {pkg} failed -- {result.stderr.strip()[:80]}")
        else:
            ok(pkg)
        progress_bar("Installing packages", i, len(PACKAGES))

# ──────────────────────────────────────────────────────────────────
# ENV FILE
# ──────────────────────────────────────────────────────────────────
def write_env():
    section("API Keys Configuration")
    global _steps_done, _steps_total
    _steps_total += 1; step("Writing .env.trading")

    if ENV_FILE.exists():
        ok(".env.trading already exists -- skipping")
        return

    ENV_FILE.write_text(textwrap.dedent("""
        # Anduril Trading Suite -- API Keys
        # Fill in the keys below. Never share this file.
        # ─────────────────────────────────────────────────────────

        # FINNHUB -- free at https://finnhub.io  (60 calls/min)
        # Used for: live quotes, Level 2, news, earnings, analyst data
        FINNHUB_API_KEY=YOUR_KEY_HERE

        # NEWSDATA.IO -- free at https://newsdata.io (200 credits/day = 2000 articles)
        # Used for: live news feed, geopolitical, macro, markets (12hr delay on free tier)
        NEWSDATA_API_KEY=YOUR_KEY_HERE

        # TWELVE DATA -- free at https://twelvedata.com (800 calls/day)
        # Used for: price history fallback, forex pairs, earnings calendar, technical indicators
        TWELVE_DATA_API_KEY=YOUR_KEY_HERE

        # ALWAYS FREE (no key needed)
        # Yahoo Finance : yfinance -- price history, charts, financials
    """).lstrip())
    ok(f"Created: {ENV_FILE}")
    warn("Open .env.trading and add your FINNHUB_API_KEY before launching")

# ──────────────────────────────────────────────────────────────────
# APP.PY
# ──────────────────────────────────────────────────────────────────
GUIDE_B64 = ""

LOGO_B64 = ""

LOGO_JPG_B64 = ""

APP_CODE_B64 = ""

def write_app():
    section("Writing Dashboard")
    global _steps_done, _steps_total
    _steps_total += 4; step("Decoding and writing app.py")

    app_code = base64.b64decode(APP_CODE_B64).decode("utf-8")
    app_path = DASH_DIR / "app.py"
    app_path.write_text(app_code, encoding="utf-8")
    ok(f"Written: {app_path}")

    step("Syntax check")
    try:
        ast.parse(app_code)
        ok("Syntax check passed")
    except SyntaxError as e:
        fail(f"Syntax error in app.py line {e.lineno}: {e.msg}")

    step("Writing logo files")
    logo_path = INSTALL_ROOT / "anduril_logo.svg"
    if not logo_path.exists():
        logo_path.write_bytes(base64.b64decode(LOGO_B64))
        ok(f"Written: {logo_path}")
    jpg_path = INSTALL_ROOT / "anduril_logo.jpg"
    if not jpg_path.exists():
        jpg_path.write_bytes(base64.b64decode(LOGO_JPG_B64))
        ok(f"Written: {jpg_path}")

    step("Writing Hedge Fund Reference Guide")
    guide_path = INSTALL_ROOT / "guide.html"
    if not guide_path.exists():
        guide_data = base64.b64decode(GUIDE_B64)
        guide_path.write_bytes(guide_data)
        ok(f"Written: {guide_path}")
    else:
        ok("Guide already exists")

# ──────────────────────────────────────────────────────────────────
# LAUNCHER ICONS
# ──────────────────────────────────────────────────────────────────
def _logo_jpg():
    return INSTALL_ROOT / "anduril_logo.jpg"

def _desktop_dir():
    for name in ("Desktop", "desktop"):
        d = Path.home() / name
        if d.exists():
            return d
    return None

def _set_macos_icon(file_path, image_path):
    script = textwrap.dedent(f"""
        use framework "AppKit"
        use scripting additions
        set iconImage to current application's NSImage's alloc()'s initWithContentsOfFile:"{image_path}"
        set targetFile to POSIX file "{file_path}"
        current application's NSWorkspace's sharedWorkspace()'s setIcon:iconImage forFile:(POSIX path of targetFile) options:0
    """).strip()
    subprocess.run(["osascript", "-l", "AppleScript", "-e", script],
                   check=True, capture_output=True)

def _write_windows_ico(jpg_path, ico_path):
    ps1 = INSTALL_ROOT / "_make_ico.ps1"
    ps1.write_text(textwrap.dedent(f"""
        Add-Type -AssemblyName System.Drawing
        $bmp = [System.Drawing.Bitmap]::FromFile('{jpg_path}')
        $hIcon = $bmp.GetHicon()
        $icon = [System.Drawing.Icon]::FromHandle($hIcon)
        $stream = [System.IO.File]::Create('{ico_path}')
        $icon.Save($stream)
        $stream.Close()
        $bmp.Dispose()
    """).strip(), encoding="utf-8")
    try:
        run(["powershell", "-NoProfile", "-ExecutionPolicy", "Bypass", "-File", str(ps1)])
    finally:
        ps1.unlink(missing_ok=True)

def _create_windows_shortcut(lnk_path, target, icon_ico, work_dir):
    ps1 = INSTALL_ROOT / "_make_shortcut.ps1"
    ps1.write_text(textwrap.dedent(f"""
        $WshShell = New-Object -ComObject WScript.Shell
        $Shortcut = $WshShell.CreateShortcut('{lnk_path}')
        $Shortcut.TargetPath = '{target}'
        $Shortcut.WorkingDirectory = '{work_dir}'
        $Shortcut.IconLocation = '{icon_ico},0'
        $Shortcut.Description = 'Anduril Trading Suite'
        $Shortcut.Save()
    """).strip(), encoding="utf-8")
    try:
        run(["powershell", "-NoProfile", "-ExecutionPolicy", "Bypass", "-File", str(ps1)])
    finally:
        ps1.unlink(missing_ok=True)

def _write_linux_desktop(dest, exec_sh, icon_jpg):
    dest.write_text(textwrap.dedent(f"""
        [Desktop Entry]
        Name=Anduril Trading
        Comment=Anduril Trading Suite
        Exec={exec_sh}
        Icon={icon_jpg}
        Terminal=true
        Type=Application
        Categories=Finance;Office;
        StartupNotify=true
    """).lstrip())
    dest.chmod(0o755)

def _apply_launcher_icon(target):
    logo = _logo_jpg()
    if not logo.exists():
        warn(f"Logo not found -- skipping icon for {target.name}")
        return
    try:
        if IS_MAC:
            _set_macos_icon(str(target.resolve()), str(logo.resolve()))
            ok(f"Icon set: {target.name}")
        elif IS_WIN:
            pass  # Windows uses .lnk with embedded icon path
        elif IS_LINUX:
            ok(f"Icon linked via .desktop: {logo.name}")
    except Exception as e:
        warn(f"Could not set icon on {target.name}: {e}")

# ──────────────────────────────────────────────────────────────────
# LAUNCHER
# ──────────────────────────────────────────────────────────────────
def write_launcher():
    section("Launch Scripts")
    global _steps_done, _steps_total
    _steps_total += 2

    if IS_WIN:
        step("Writing launch.bat")
        bat = INSTALL_ROOT / "launch.bat"
        bat.write_text(
            f'''@echo off
call "{VENV_DIR}\\Scripts\\activate.bat"
echo.
echo   Anduril Trading Suite starting...
echo   Opening browser at http://127.0.0.1:8050
echo   Guide: {INSTALL_ROOT}\\guide.html
echo   Press Ctrl+C to stop.
echo.
timeout /t 1 /nobreak >nul
start "" "http://127.0.0.1:8050"
python "{DASH_DIR}\\app.py"
''')
        ok(f"launch.bat: {bat}")

        logo = _logo_jpg()
        ico_path = INSTALL_ROOT / "anduril_logo.ico"
        if logo.exists():
            step("Writing shortcut icon (.ico)")
            _write_windows_ico(str(logo.resolve()), str(ico_path.resolve()))
            ok(f"Written: {ico_path}")

        step("Desktop shortcut (.lnk)")
        desktop = _desktop_dir()
        if desktop:
            shortcut = desktop / "Anduril Trading.lnk"
            if logo.exists() and ico_path.exists():
                _create_windows_shortcut(str(shortcut.resolve()), str(bat.resolve()),
                                         str(ico_path.resolve()), str(INSTALL_ROOT.resolve()))
            else:
                _create_windows_shortcut(str(shortcut.resolve()), str(bat.resolve()),
                                         str(bat.resolve()), str(INSTALL_ROOT.resolve()))
            ok(f"Desktop shortcut: {shortcut}")
        else:
            warn("Desktop not found -- run launch.bat manually")

    else:  # Mac / Linux
        step("Writing launch.sh")
        sh = INSTALL_ROOT / "launch.sh"
        sh.write_text(
            f'''#!/usr/bin/env bash
source "{VENV_DIR}/bin/activate"
echo ""
echo "  Anduril Trading Suite starting..."
echo "  Opening browser at http://127.0.0.1:8050"
echo "  Press Ctrl+C to stop.  |  Open guide: {INSTALL_ROOT}/guide.html"
echo ""
sleep 1
open "http://127.0.0.1:8050" 2>/dev/null || xdg-open "http://127.0.0.1:8050" 2>/dev/null || true
python "{DASH_DIR}/app.py"
''')
        sh.chmod(0o755)
        ok(f"launch.sh: {sh}")

        desktop = _desktop_dir()
        logo = _logo_jpg()

        if IS_MAC:
            step("Desktop shortcut (.command)")
            cmd_script = INSTALL_ROOT / "Anduril Trading.command"
            cmd_script.write_text(
                f'''#!/usr/bin/env bash
source "{VENV_DIR}/bin/activate"
open "http://127.0.0.1:8050" 2>/dev/null || xdg-open "http://127.0.0.1:8050" 2>/dev/null || true
python "{DASH_DIR}/app.py"
''')
            cmd_script.chmod(0o755)
            _apply_launcher_icon(cmd_script)
            if desktop:
                dest = desktop / "Anduril Trading.command"
                shutil.copy(cmd_script, dest)
                dest.chmod(0o755)
                _apply_launcher_icon(dest)
                ok(f"Desktop shortcut: {dest}")
            else:
                warn("Desktop not found -- run launch.sh manually")

        elif IS_LINUX:
            step("Desktop shortcut (.desktop)")
            desktop_entry = INSTALL_ROOT / "Anduril Trading.desktop"
            _write_linux_desktop(desktop_entry, str(sh.resolve()), str(logo.resolve()))
            ok(f"Written: {desktop_entry}")
            if desktop:
                dest = desktop / "Anduril Trading.desktop"
                shutil.copy(desktop_entry, dest)
                dest.chmod(0o755)
                ok(f"Desktop shortcut: {dest}")
            apps_dir = Path.home() / ".local" / "share" / "applications"
            apps_dir.mkdir(parents=True, exist_ok=True)
            menu_entry = apps_dir / "anduril-trading.desktop"
            shutil.copy(desktop_entry, menu_entry)
            menu_entry.chmod(0o755)
            ok(f"Applications menu: {menu_entry}")
        else:
            warn("Unknown Unix platform -- run launch.sh manually")

# ──────────────────────────────────────────────────────────────────
# SUMMARY
# ──────────────────────────────────────────────────────────────────
def print_summary():
    print()
    print(clr(C, "  " + "═" * 63))
    print(clr(C, "  ║") + " " * 63 + clr(C, "║"))
    title = "INSTALLATION COMPLETE"
    pad = (61 - len(title)) // 2
    print(clr(C, "  ║") + " " * (pad+2) + clr(G, title) + " " * (61 - pad - len(title)) + clr(C, "║"))
    print(clr(C, "  ║") + " " * 63 + clr(C, "║"))
    print(clr(C, "  " + "═" * 63))
    print()

    lines = [
        ("", ""),
        ("WHAT WAS INSTALLED", "header"),
        (f"Python {sys.version.split()[0]}",                   "ok"),
        (f"Dashboard  →  {DASH_DIR / 'app.py'}",              "ok"),
        ("All Python packages",                                 "ok"),
        ("", ""),
        ("NEXT STEPS", "header"),
        ("1. Open this file and add your Finnhub key:", "plain"),
        (f"     {ENV_FILE}",                                    "dim"),
        ("   Get a free key at:  https://finnhub.io",          "dim"),
        ("", ""),
        ("2b. Add your NewsData.io key (for Live News feed):", "plain"),
        (f"     {ENV_FILE}",                                    "dim"),
        ("   NEWSDATA_API_KEY=your_key  -- free at newsdata.io","dim"),
        ("", ""),
        ("2. Launch Anduril:", "plain"),
    ]

    if IS_WIN:
        lines += [
            (f"   Double-click  Anduril Trading.lnk  on your Desktop",  "yellow"),
            (f"   OR run:  {INSTALL_ROOT / 'launch.bat'}",              "dim"),
        ]
    elif IS_LINUX:
        lines += [
            (f"   Double-click  Anduril Trading.desktop  on Desktop",   "yellow"),
            (f"   OR run:  bash {INSTALL_ROOT / 'launch.sh'}",          "dim"),
        ]
    else:
        lines += [
            (f"   Double-click  Anduril Trading.command  on Desktop",   "yellow"),
            (f"   OR run:  bash {INSTALL_ROOT / 'launch.sh'}",          "dim"),
        ]

    lines += [
        ("", ""),
        ("3. Browser opens at  http://127.0.0.1:8050",         "plain"),
        ("", ""),
        ("PAGES", "header"),
        ("  Watchlist    5 groups × 10 tickers  |  live prices","ok"),
        ("  Conviction   6-tab deep analysis before any trade", "ok"),
        ("  Adv Chart    Full technical charting + annotations", "ok"),
        ("  Level 2      Order book + pressure + tape",         "ok"),
        ("  Screener     Industry & keyword scanner",           "ok"),
        ("  News         90-day news + earnings history",       "ok"),
        ("  Live News    RSS + NewsData.io geopolitical feed",  "ok"),
        ("  Financials   Valuation metrics + analyst ratings",  "ok"),
        ("", ""),
        ("REFERENCE GUIDE", "header"),
        ("  guide.html   Hedge Fund Investing Guide (offline)",  "ok"),
        ("  20 tabs: Fundamentals, Technicals, Quant, Macro,",   "dim"),
        ("  Options, Crypto, Calculators, Screener + more",      "dim"),
        ("", ""),
    ]

    for text, style in lines:
        if style == "header":
            print(f"  {clr(C, text)}")
        elif style == "ok":
            print(f"  {clr(G, '  ✓')}  {text}")
        elif style == "yellow":
            print(f"  {clr(Y, '  ▸')}  {clr(Y, text)}")
        elif style == "dim":
            print(f"       {clr(DIM, text)}")
